// Attestation structure (EIP-712)
struct Attestation {
  uint256 tokenId;
  address ownerAddress;
  uint256 targetChainId;       // 8453 (Base)
  address targetAssociationCore;
  bytes32 action;              // keccak256("REGISTER")
  uint256 nonce;               // 256 random bits
  uint256 deadline;            // UNIX timestamp
}

attestation.flowCode:
// Full flow
// 1. Client calls POST /api/attest { tokenId, walletAddress }
// 2. Backend verifies ownerOf(tokenId) on Ethereum
// 3. Backend signs the EIP-712 attestation
// 4. Client submits register(attestation, signature)
// 5. Core verifies:
