// Publishing an on-chain work (WorkRegistry.sol)
function publish(
  string calldata content,     // data:text/html;base64,...
  uint256 authorTokenId,       // AUTHOR role
  uint256 curatorTokenId,      // CURATOR role
  uint256 rapporteurTokenId    // RAPPORTEUR role
) external onlyRole(RAPPORTEUR_ROLE) {
  works[++workCount] = Work({
    id:               workCount,
    content:          content,   // stored in state
    authorTokenId:    authorTokenId,
    curatorTokenId:   curatorTokenId,
    rapporteurTokenId:rapporteurTokenId,
    publishedAt:      block.timestamp,
    archived:         false
  });
  emit WorkPublished(workCount, authorTokenId);
}

// Reading on the frontend
const { data } = useReadContract({
  functionName: "getWork",
  args: [workId],
});
